import os
import json
import pickle
import argparse
from collections import defaultdict

import numpy as np
import gymnasium as gym
import humanoid_bench  # noqa: F401
from stable_baselines3 import PPO


FALLBACK_TASKS = {
    "h1hand-door-v0": ["h1hand-pole-v0", "h1hand-walk-v0", "h1hand-stand-v0"],
    "h1hand-reach-v0": ["h1hand-balance_simple-v0", "h1hand-pole-v0", "h1hand-walk-v0"],
    "h1hand-push-v0": ["h1hand-pole-v0", "h1hand-walk-v0", "h1hand-balance_simple-v0"],
    "h1hand-package-v0": ["h1hand-pole-v0", "h1hand-stand-v0", "h1hand-walk-v0"],
}


def resolve_eval_config(data_path):
    candidates = [
        os.path.join(data_path, "eval_config.json"),
        os.path.join(data_path, "humanoidbench_test", "eval_config.json"),
        os.path.join("/data", "humanoidbench_test", "eval_config.json"),
        os.path.join("/data", "eval_config.json"),
        os.path.join("local_eval", "eval_config.json"),
    ]
    for path in candidates:
        if os.path.exists(path):
            return path
    raise FileNotFoundError(f"Could not find eval_config.json. Tried: {candidates}")


def find_task_dir(checkpoint_root, task_id):
    direct = os.path.join(checkpoint_root, task_id)
    if os.path.isdir(direct):
        return direct
    nested = os.path.join(checkpoint_root, "per_task", task_id)
    if os.path.isdir(nested):
        return nested
    return None


def choose_source_task(checkpoint_root, task_id):
    if find_task_dir(checkpoint_root, task_id) is not None:
        return task_id
    for cand in FALLBACK_TASKS.get(task_id, []):
        if find_task_dir(checkpoint_root, cand) is not None:
            return cand
    available = []
    for name in sorted(os.listdir(checkpoint_root)) if os.path.isdir(checkpoint_root) else []:
        if name.startswith("h1hand-") and find_task_dir(checkpoint_root, name) is not None:
            available.append(name)
    nested_root = os.path.join(checkpoint_root, "per_task")
    if os.path.isdir(nested_root):
        for name in sorted(os.listdir(nested_root)):
            if name.startswith("h1hand-") and find_task_dir(checkpoint_root, name) is not None and name not in available:
                available.append(name)
    if available:
        return available[0]
    return None


def load_vecnorm_stats(task_dir):
    path = os.path.join(task_dir, "vecnormalize.pkl")
    if not os.path.exists(path):
        return None
    with open(path, "rb") as f:
        obj = pickle.load(f)
    obs_rms = getattr(obj, "obs_rms", None)
    if obs_rms is None:
        return None
    mean = np.asarray(obs_rms.mean, dtype=np.float32)
    var = np.asarray(obs_rms.var, dtype=np.float32)
    clip_obs = float(getattr(obj, "clip_obs", 10.0))
    epsilon = float(getattr(obj, "epsilon", 1e-8))
    return {"mean": mean, "var": var, "clip_obs": clip_obs, "epsilon": epsilon}


def normalize_obs(obs, stats):
    if stats is None:
        return np.asarray(obs, dtype=np.float32)
    x = np.asarray(obs, dtype=np.float32)
    x = (x - stats["mean"]) / np.sqrt(stats["var"] + stats["epsilon"])
    x = np.clip(x, -stats["clip_obs"], stats["clip_obs"])
    return x.astype(np.float32)


def load_task_bundle(checkpoint_root, requested_task_id, cache):
    source_task = choose_source_task(checkpoint_root, requested_task_id)
    if source_task is None:
        raise FileNotFoundError(f"No available task checkpoints under {checkpoint_root}")
    if source_task in cache:
        return cache[source_task]

    task_dir = find_task_dir(checkpoint_root, source_task)
    model_path = os.path.join(task_dir, "final_model")
    if not (os.path.exists(model_path) or os.path.exists(model_path + ".zip")):
        zips = sorted([x for x in os.listdir(task_dir) if x.endswith(".zip")])
        if not zips:
            raise FileNotFoundError(f"No checkpoint zip found in {task_dir}")
        model_path = os.path.join(task_dir, zips[-1])
    model = PPO.load(model_path, device="cpu")
    stats = load_vecnorm_stats(task_dir)
    cache[source_task] = (model, stats, source_task)
    return cache[source_task]


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument("--data_path", required=True)
    parser.add_argument("--checkpoint", required=True)
    parser.add_argument("--output", required=True)
    args = parser.parse_args()

    cfg_path = resolve_eval_config(args.data_path)
    with open(cfg_path, "r") as f:
        cfg = json.load(f)

    cache = {}
    per_episode = []

    for task_spec in cfg["tasks"]:
        task_id = task_spec["task_id"]
        max_steps = int(task_spec["max_episode_steps"])
        success_bar = float(task_spec["success_bar"])
        info_has_success = bool(task_spec.get("info_has_success", False))
        model, obs_stats, source_task = load_task_bundle(args.checkpoint, task_id, cache)

        for ep_idx, seed in enumerate(task_spec["seeds"]):
            env = gym.make(task_id)
            obs, _ = env.reset(seed=int(seed))
            ep_reward = 0.0
            ep_info_success = 0

            for _ in range(max_steps):
                model_obs = normalize_obs(obs, obs_stats)
                action, _ = model.predict(model_obs, deterministic=True)
                action = np.asarray(action, dtype=np.float32)
                action = np.clip(action, env.action_space.low, env.action_space.high)
                obs, reward, terminated, truncated, info = env.step(action)
                ep_reward += float(reward)
                if info_has_success and int(info.get("success", 0)) > 0:
                    ep_info_success = 1
                if terminated or truncated:
                    break
            env.close()

            ep_success = int(ep_reward >= success_bar)
            if info_has_success:
                ep_success = max(ep_success, ep_info_success)
            per_episode.append({
                "task_id": task_id,
                "episode_id": ep_idx,
                "seed": int(seed),
                "reward": round(ep_reward, 4),
                "success": ep_success,
                "source_task": source_task,
            })

    tk_n, tk_s, tk_r = defaultdict(int), defaultdict(int), defaultdict(float)
    for ep in per_episode:
        tk_n[ep["task_id"]] += 1
        tk_s[ep["task_id"]] += ep["success"]
        tk_r[ep["task_id"]] += ep["reward"]
    per_task = {
        t: {
            "success_rate": tk_s[t] / tk_n[t],
            "mean_reward": tk_r[t] / tk_n[t],
            "n_episodes": tk_n[t],
        }
        for t in tk_n
    }

    results = {
        "success_rate": sum(e["success"] for e in per_episode) / max(len(per_episode), 1),
        "mean_reward": sum(e["reward"] for e in per_episode) / max(len(per_episode), 1),
        "total_episodes": len(per_episode),
        "per_task": per_task,
        "per_episode": per_episode,
    }
    with open(args.output, "w") as f:
        json.dump(results, f)


if __name__ == "__main__":
    main()
